use super::{ok,ok_null};use crate::common::{ApiResponse,AppError,I64String,PageQuery,PageResult};use crate::modules::system::AppState;use crate::modules::system::dto::job_request::JobSaveRequest;use crate::modules::system::dto::status_update_request::StatusUpdateRequest;use crate::modules::system::entity::{sys_job::SysJob,sys_job_run_log::SysJobRunLog};use crate::modules::system::service::job_service;use axum::{Json,extract::{Path,Query,State}};
pub async fn list(State(s):State<AppState>,Query(q):Query<PageQuery>)->Result<Json<ApiResponse<PageResult<SysJob>>>,AppError>{Ok(ok(job_service::list(s.database.as_ref(),q.normalize()?).await?))}pub async fn scripts()->Result<Json<ApiResponse<Vec<String>>>,AppError>{let path=std::env::current_dir().map_err(|e|AppError::system(e.to_string()))?.join("..\\scripts");let mut out=Vec::new();if let Ok(mut r)=tokio::fs::read_dir(path).await{while let Ok(Some(e))=r.next_entry().await{if e.file_type().await.map(|t|t.is_file()).unwrap_or(false){out.push(e.file_name().to_string_lossy().to_string())}}}out.sort();Ok(ok(out))}pub async fn detail(State(s):State<AppState>,Path(id):Path<i64>)->Result<Json<ApiResponse<SysJob>>,AppError>{Ok(ok(job_service::detail(s.database.as_ref(),id).await?))}pub async fn create(State(s):State<AppState>,Json(r):Json<JobSaveRequest>)->Result<Json<ApiResponse<I64String>>,AppError>{Ok(ok(job_service::create(s.database.as_ref(),r).await?))}pub async fn update(State(s):State<AppState>,Path(id):Path<i64>,Json(r):Json<JobSaveRequest>)->Result<Json<ApiResponse<()>>,AppError>{job_service::update(s.database.as_ref(),id,r).await?;Ok(ok_null())}pub async fn delete(State(s):State<AppState>,Path(id):Path<i64>)->Result<Json<ApiResponse<()>>,AppError>{job_service::delete(s.database.as_ref(),id).await?;Ok(ok_null())}pub async fn status(State(s):State<AppState>,Path(id):Path<i64>,Json(r):Json<StatusUpdateRequest>)->Result<Json<ApiResponse<()>>,AppError>{job_service::status(s.database.as_ref(),id,r.status).await?;Ok(ok_null())}pub async fn run(State(s):State<AppState>,Path(id):Path<i64>)->Result<Json<ApiResponse<()>>,AppError>{let db=s.database.ok_or_else(||AppError::system("Rbatis database is not configured"))?;job_service::run(db,id).await?;Ok(ok_null())}pub async fn run_logs(State(s):State<AppState>,Query(q):Query<PageQuery>,Path(id):Path<i64>)->Result<Json<ApiResponse<PageResult<SysJobRunLog>>>,AppError>{Ok(ok(job_service::run_logs(s.database.as_ref(),q.normalize()?,Some(id)).await?))}pub async fn all_run_logs(State(s):State<AppState>,Query(q):Query<PageQuery>)->Result<Json<ApiResponse<PageResult<SysJobRunLog>>>,AppError>{Ok(ok(job_service::run_logs(s.database.as_ref(),q.normalize()?,None).await?))}
